using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using System.Security.Claims;

namespace InvoiceApi.Controllers
{
    public class Invoice
    {
        public int Id { get; set; }
        public string UserId { get; set; } = string.Empty;
        public string InvoiceNumber { get; set; } = string.Empty;
        public decimal Amount { get; set; }
        public DateTime CreatedDate { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    public interface IInvoiceRepository
    {
        Task<Invoice?> GetByIdAsync(int invoiceId);
    }

    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class InvoicesController : ControllerBase
    {
        private readonly IInvoiceRepository _invoiceRepository;

        public InvoicesController(IInvoiceRepository invoiceRepository)
        {
            _invoiceRepository = invoiceRepository;
        }

        [HttpGet("{invoiceId:int}")]
        public async Task<IActionResult> GetInvoice(int invoiceId)
        {
            if (invoiceId <= 0)
            {
                return BadRequest("Invalid invoice ID.");
            }

            var currentUserId = User.FindFirstValue(ClaimTypes.NameIdentifier);

            if (string.IsNullOrEmpty(currentUserId))
            {
                return Unauthorized("User identity could not be determined.");
            }

            var invoice = await _invoiceRepository.GetByIdAsync(invoiceId);

            if (invoice == null)
            {
                return NotFound("Invoice not found.");
            }

            // Prevent broken access control: ensure the authenticated user owns this invoice
            // Unless the user has an admin role that permits viewing all invoices
            bool isAdmin = User.IsInRole("Admin");

            if (!isAdmin && invoice.UserId != currentUserId)
            {
                // Return NotFound instead of Forbidden to avoid revealing that the resource exists
                return NotFound("Invoice not found.");
            }

            return Ok(new
            {
                invoice.Id,
                invoice.InvoiceNumber,
                invoice.Amount,
                invoice.CreatedDate,
                invoice.Description
            });
        }
